/**
 * 总结报告阶段：
 * 汇总所有阶段成果，生成最终报告
 * - SummaryAgent: AI 交互执行
 * - SummaryPhase: Workflow 调度入口
 */

import type { PhaseId } from "../models.js";
import { SpecWorkflowAgent } from "./base_agent.js";
import { BasePhase } from "./base_phase.js";

export class SummaryAgent extends SpecWorkflowAgent {
  readonly phaseId: PhaseId = "summary";
  readonly promptTemplate = "spec_summary";
  readonly phaseName = "总结报告";

  protected getArtifactFileName(): string {
    return "summary.md";
  }
}

export class SummaryPhase extends BasePhase {
  readonly phaseId: PhaseId = "summary";
  readonly phaseName = "总结报告";

  protected override createAgent(): SpecWorkflowAgent {
    return new SummaryAgent();
  }
}
